import React, { Component } from 'react'
import {Table, Icon} from 'semantic-ui-react'
import { Link, withPrefix } from "gatsby";

const tableData = [
  { name: 'Caracole', price: '670€', type: 'gîte', persons: 6, rooms:3, nights:7 },
  { name: 'Colimaçon', price: '670€', type: 'gîte', persons: 7, rooms:3, nights:7 },
  { name: 'Hôtel B&B Caen Sud', price: '56€', type: 'hôtel', persons: 2, rooms:1, nights:1 },
  { name: 'Hôtel Ibis Budget Bretteville', price: '69€', type: 'hôtel', persons: 2, rooms:1, nights:1 },
]

export default class SortableTable extends Component {
  constructor(props){
    super(props);
       this.state={
        column: null,
        data: props.data,
        direction: null,
        };
     }
  handleSort = (clickedColumn) => () => {
    const { column, data, direction } = this.state

    if (column !== clickedColumn) {
      this.setState({
        column: clickedColumn,
        data: _.sortBy(data, [clickedColumn]),
        direction: 'ascending',
      })

      return
    }

    this.setState({
      data: data.reverse(),
      direction: direction === 'ascending' ? 'descending' : 'ascending',
    })
  }

  render() {
    const { column, data, direction } = this.state

    return (
      <Table sortable celled fixed unstackable>
        <Table.Header>
          <Table.Row>
            <Table.HeaderCell
              sorted={column === 'name' ? direction : null}
              onClick={this.handleSort('name')}
            >
              <Icon name="fas fa-user-tag" size="big"/>
              <span class="mobile hidden">Nom</span>
            </Table.HeaderCell>
            <Table.HeaderCell
              sorted={column === 'type' ? direction : null}
              onClick={this.handleSort('type')}
            >
              <Icon.Group size="big">
              <Icon name="fas fa-home"/>
              <Icon corner name="fas fa-cog"/>
              </Icon.Group>
              <span class="mobile hidden">Type</span>
            </Table.HeaderCell>
            <Table.HeaderCell
              sorted={column === 'price' ? direction : null}
              onClick={this.handleSort('price')}
            >
              <Icon name="fas fa-coins" size="big"/>
              <span class="mobile hidden">Prix</span>
            </Table.HeaderCell>
            <Table.HeaderCell
              sorted={column === 'persons' ? direction : null}
              onClick={this.handleSort('persons')}
            >
             <Icon name="fas fa-users" size="big"/>
             <span class="mobile hidden">Personnes</span>
            </Table.HeaderCell>
            <Table.HeaderCell
              sorted={column === 'rooms' ? direction : null}
              onClick={this.handleSort('rooms')} className="mobile hidden"
            >
              <Icon name="fas fa-moon" size="big"/>
              <span class="mobile hidden">Nuités</span>
            </Table.HeaderCell>
            <Table.HeaderCell
              sorted={column === 'nights' ? direction : null}
              onClick={this.handleSort('nights')} className="mobile hidden"
              >
              <Icon name="fas fa-bed" size="big"/>
              <span class="mobile hidden">Chambres</span>
            </Table.HeaderCell>
          </Table.Row>
        </Table.Header>
        <Table.Body>
          {data.map(({persons, price, type, name, nights, rooms, link }) => (
            
            <Table.Row key={name}>
              <Table.Cell><Link to={link}>{name}</Link></Table.Cell>
              <Table.Cell>
              {(() => {
                  if (type.length>=1) {type=type.reverse().join(', ')}
                  switch(type){
                    case 'chambre':
                        return <Icon name="fas fa-door-open" className="mobileOnly" size="big"></Icon>
                    case 'hôtel':
                        return <Icon name="fas fa-hotel" className="mobileOnly" size="big"></Icon>
                    case 'gîte':
                        return <Icon name="fas fa-home" className="mobileOnly" size="big"></Icon>
                    case 'gîte, chambre':
                        return <React.Fragment><Icon name="fas fa-door-open" size="big" className="mobileOnly"/><Icon name="fas fa-home" size="big" className="mobileOnly"/></React.Fragment>
                    default:
                      null
                }
              })()}
              
                <span class="mobile hidden">{type} </span></Table.Cell>
              <Table.Cell>{price}</Table.Cell>
              <Table.Cell>{persons}</Table.Cell>
              <Table.Cell className="mobile hidden">{nights}</Table.Cell>
              <Table.Cell className="mobile hidden">{rooms}</Table.Cell>
            </Table.Row>
          ))}
        </Table.Body>
      </Table>
    )
  }
}
